// Transformer les données pour Horizon API
const items = $input.all();
const grouped = {
  encours: [],
  rendezvous: [],
  realisation: [],
  joursouvert: []
};

for (const item of items) {
  const data = item.json;
  const type = data.data_type;
  delete data.data_type;

  if (grouped[type]) {
    grouped[type].push(data);
  }
}

// Retourner un item par type
const output = [];

if (grouped.encours.length > 0) {
  output.push({
    json: {
      type: 'encours',
      data: grouped.encours.map(e => ({
        praticien: e.praticien || 'Global',
        dureeTotaleARealiser: parseFloat(e.duree_totale_a_realiser) || 0,
        montantTotalAFacturer: parseFloat(e.montant_total_a_facturer) || 0,
        rentabiliteHoraire: parseFloat(e.rentabilite_horaire) || 0,
        rentabiliteJoursTravailles: parseFloat(e.rentabilite_jours_travailles) || 0,
        patientsEnCours: parseFloat(e.patients_en_cours) || 0
      }))
    }
  });
}

if (grouped.rendezvous.length > 0) {
  output.push({
    json: {
      type: 'rendezvous',
      data: grouped.rendezvous.map(r => ({
        praticien: r.praticien,
        mois: r.mois,
        nbRdv: parseFloat(r.nb_rdv) || 0,
        dureeTotaleRdv: parseFloat(r.duree_totale_rdv) || 0,
        nbPatients: parseFloat(r.nb_patients) || 0,
        nbNouveauxPatients: parseFloat(r.nb_nouveaux_patients) || 0
      }))
    }
  });
}

if (grouped.realisation.length > 0) {
  output.push({
    json: {
      type: 'realisation',
      data: grouped.realisation.map(r => ({
        praticien: r.praticien,
        mois: r.mois,
        nbPatients: parseFloat(r.nb_patients) || 0,
        montantFacture: parseFloat(r.montant_facture) || 0,
        montantEncaisse: parseFloat(r.montant_encaisse) || 0
      }))
    }
  });
}

if (grouped.joursouvert.length > 0) {
  output.push({
    json: {
      type: 'joursouvert',
      data: grouped.joursouvert.map(j => ({
        praticien: j.praticien,
        mois: j.mois,
        nbHeures: parseFloat(j.nb_heures) || 0
      }))
    }
  });
}

return output;
